    change_type, base_version_id, version_note, status_at_submit, submitted_at
) values (
    #{productId}, #{versionNo}, #{baseInfoJson}, #{paramsJson}, #{versionStatus},
    #{changeType}, #{baseVersionId}, #{versionNote}, #{statusAtSubmit}, #{submittedAt}
