mapper.select:
select id, product_id, version_no, base_info_json, params_json, version_status,
       change_type, base_version_id, version_note, status_at_submit, submitted_at, created_at
from advisor_product_version
where product_id = #{productId}
  and version_no = #{versionNo}
limit 1

mapper.update:
update advisor_product_version
set version_status = #{versionStatus}
where id = #{id}
